mapper.select:
select barcode from v_itemhistory where (kind = 'BARCODE' or kind = 'PALLET') and barcode in
#{barcode}
and useyn ='Y' and laststatus between 1 and 9

SELECT PNO, QTY
FROM T_SCM_BARCODE
WHERE BARCODE = #{barcode}

mapper.update:
update t_scm_barcode
set laststatus = #{laststatus},
    lastfactory = #{factory},
    laststorage = #{storage}
where barcode = #{barcode}

mapper.select:
select a.iid, a.itemcode, to_number(a.qty) as qty, nvl(a.source,' ') as source, a.storage, substr(a.ymdhms,9,6) as time from t_wms_inbound a left outer join t_wms_location b on a.barcode = b.barcode and b.useyn ='Y' where a.sdate = #{date} and a.storage = #{storage}
and a.custcode = #{custcode}
and a.custname = #{custname}
and a.source = 'INCOMING' and a.factory = #{factory} and a.useyn = 'Y' order by a.ymdhms desc

SELECT
    a.sdate,
    a.factory,
    a.storage,
    a.itemcode,
    SUM(a.qty) as sumqty
FROM t_wms_inbound a
WHERE a.useyn = 'Y'
AND A.SOURCE = 'INCOMING'
AND a.sdate = #{date}
AND a.storage = #{storage}
AND a.factory = #{factory}

    AND a.custcode = #{custcode}


    AND a.custname = #{custname}

GROUP BY a.sdate, a.itemcode, a.factory, a.storage
